css:
.loader {color: var(--loader-color, #059669);
  --loader-secondary-color: #2dd4bf;
  --loader-bg: #ffffff;
   width: 60px;
   height: 16px;
   display: flex;
   justify-content: space-between;
   animation: l3-0 2s infinite alternate;
}
.loader:before, .loader:after  {
  content: "";
   width: 16px;
   background: var(--loader-color, #059669);
   animation: l3-1 1s infinite alternate;
}
.loader:after  {
  background: var(--loader-secondary-color, #2dd4bf);
   --s:-1;
}
@keyframes l3-0  {
  0%,40% {transform: rotate(0)}
80%,100% {transform: rotate(.5turn)}
}
@keyframes l3-1  {
  80%,100% {transform: translate(calc(var(--s,1)*14px))}
}
